/**
 * 将传入的对象解析为一个数组并返回
 * 如果不是数组则返回一个空的数组
 */
export const parseArray = o => {
    if (Object.prototype.toString.call(o) === '[object Array]')
        return o;
    try {
        let arr = JSON.parse(String(o));
        return Object.prototype.toString.call(arr) === '[object Array]' ? arr : [];
    } catch (e) {
        return [];
    }
}

export const parseObject = o => {
    if (Object.prototype.toString.call(o) === '[object Object]')
        return o;
    try {
        let arr = JSON.parse(String(o));
        return Object.prototype.toString.call(arr) === '[object Object]' ? arr : [];
    } catch (e) {
        return [];
    }
}

/**
 * 判断是否为Object
 */
export const isObject = o => {
    if (Object.prototype.toString.call(o) === '[object Object]')
        return true;
    try {
        return Object.prototype.toString.call(JSON.parse(o)) === '[object Object]';
    } catch (e) {
        return false;
    }
}
