import Vue from 'vue'
import Router from 'vue-router'

Vue.use(Router);

// 所有路由的数组
export const routes = [
    {path: '/', redirect: '/login'},
    {name: 'login', path: '/login', component: () => import('@/pages/Login'), meta: {title: '登录'}},
    {name: 'main', path: '/main', component: () => import('@/pages/Main'), children: []},
    {name: 'detail', path: '/detail', component: () => import('@/pages/index/Detail')},
    {name: '404', path: '*', component: () => import('@/pages/404')}
];

export const router = new Router({mode: 'history', routes: routes});

// 使用此方法将routes添加进router
router.add = () => {
    router.matcher = new Router({mode: 'history'}).matcher; // 先将router对象重置，可防止重复name路由报警
    router.addRoutes(routes); // 添加路由
};

// 路由监听
router.beforeEach((to, from, next) => {
    document.title = to.meta?.title || '';
    next();
});

// 重复路由跳转防报错
const originalPush = Router.prototype.push;
Router.prototype.push = function push(location) {
    return originalPush.call(this, location).catch(err => err)
};

const originalReplace = Router.prototype.replace;
Router.prototype.replace = function replace(location) {
    return originalReplace.call(this, location).catch(err => err)
};
