import Vue from 'vue'
import App from './App.vue'
import {router} from '@/plugins/router'
import store from '@/plugins/vuex'
import { sync } from 'vuex-router-sync'
// element-ui
import ElementUI from 'element-ui'
import "@/assets/css/element.less" // 包含了@/assets/css/theme/index.less
import "@/assets/css/global.less"
import "@/assets/css/layout.less"
import 'element-ui/lib/theme-chalk/display.css' // element自带的响应式布局
// 页面引导
import IntroJs from 'intro.js'
import 'intro.js/minified/introjs.min.css'
// import 'intro.js/themes/introjs-royal.css' // 更换主题
// less
import less from 'less'
// 背景插件
import VueParticles from 'vue-particles'

Vue.use(ElementUI, {size: 'small'})
Vue.use(IntroJs)
Vue.use(less)
Vue.use(VueParticles)
sync(store, router, {moduleName: 'route'})

Vue.config.productionTip = false
Vue.config.errorHandler = (error) => { // 全局异常处理 https://www.jianshu.com/p/93fe184da4c2
    ElementUI.Message.warning({message: error, showClose: true});
}

new Vue({
    router,
    store,
    'render': h => h(App),
}).$mount('#app')
