import Vue from 'vue'
import Vuex from 'vuex'

Vue.use(Vuex)

export default new Vuex.Store({
    strict: true, // 严格模式，只能通过mutations改变state的值
    state: {
        drawer: false // 通过头部控制移动端菜单抽屉用的
    },
    mutations: {
        drawer(state, drawer) {
            state.drawer = drawer;
        }
    }
})
