import {router, routes} from "@/plugins/router";
import CustomStorage from "@/plugins/common/CustomStorage";
import menus from "@/assets/json/menus.json";

export const list = () => new Promise(resolve => {
    setTimeout(() => {
        CustomStorage.setItem('_menus', JSON.stringify(menus));
        addToRouter();
        resolve({records: menus});
    }, 500);
}); // 模拟接口请求

export const addToRouter = () => {
    let menus;
    try {
        menus = JSON.parse(CustomStorage.getItem('_menus'));
    } catch (e) {
        menus = [];
    }
    if (Object.prototype.toString.call(menus) === '[object Array]' && menus.length > 0) {
        let main = routes.find(i => i.name === 'main');
        if (main) {
            if (Object.prototype.toString.call(main.children) !== '[object Array]')
                main.children = [];
            let firstMenu;
            menus.forEach(i => {
                if (menus.every(e => e.parentId !== i.id)) { // 没有子菜单才添加路由
                    let name = i.page.toLowerCase();
                    firstMenu = firstMenu || name;
                    if (!main.children.some(j => j.name === name)) {
                        main.children.push({
                            name: name,
                            path: name,
                            meta: {
                                isMenu: true,
                                title: i.title
                            },
                            component: () => import('@/pages/' + i.page)
                        });
                    }
                }
            });
            router.add();
            if (firstMenu && CustomStorage.getItem('_is_from_login')) { // 如果是从登陆界面进来的就跳转到第一个菜单
                router.push({name: firstMenu}).then(() => CustomStorage.setItem('_is_from_login', ''));
            }

        }
    }
}
