<template>
    <div class="h-100 center">
        <vue-particles style="position: fixed; top: 0; width: 100%; z-index: -9999"></vue-particles>
        <router-view/>
    </div>
</template>
<script>
    import {addToRouter} from '@/plugins/axios/api/menu'
    import axios from '@/plugins/axios'

    export default {
        beforeCreate() {
            addToRouter();
            this.$router.replace(window.location.pathname + window.location.search);
        },
        data() {
            return {
                uploading: false,
                fileList: []
            }
        },
        methods: {
            pushFile(e) {
                this.fileList.push(e.file);
            },
            upload() {
                this.uploading = true;
                let data = new FormData();
                this.fileList.forEach(e => data.append('file', e));
                axios.post('upload', data, {
                    headers: {
                        'Content-Type': 'multipart/form-data'
                    },
                    responseType: 'blob'
                }).then(() => {
                    this.$refs.upload.clearFiles();
                    this.fileList = [];
                    this.$message.success('下载成功！');
                }).finally(() => this.uploading = false);
            }
        }
    }

</script>
