// 自定义的本地存储功能，防止无痕模式或不支持localStorage、sessionStorage的浏览器无法记录本地数据导致功能失效
import {parseObject} from "@/plugins/common/Func";

export default {
    setItem: (key, value) => {
        localStorage.setItem(key, value);
        sessionStorage.setItem(key, value);
        let o = parseObject(window.name);
        o[key] = value;
        window.name = JSON.stringify(o);
    },
    getItem: (key) => {
        return localStorage.getItem(key) || sessionStorage.getItem(key) || parseObject(window.name)[key];
    },
    removeItem: (key) => {
        localStorage.removeItem(key);
        sessionStorage.removeItem(key);
        let o = parseObject(window.name);
        delete o[key];
        window.name = JSON.stringify(o);
    },
    clear: () => {
        localStorage.clear();
        sessionStorage.clear();
        window.name = '{}';
    },
}
